import{_ as t,o as r,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"42B. Night Shift Rostering Principles Other Than Permanent Night","description":"","frontmatter":{"title":"42B. Night Shift Rostering Principles Other Than Permanent Night","eba":"Nurses and Midwives 2024-2028","topics":["hours","shift-work"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/42B-night-shift-rostering-principles-other-than-permanent-night.md","filePath":"ebas/nurses-midwives/hours-of-work/42B-night-shift-rostering-principles-other-than-permanent-night.md"}'),s={name:"ebas/nurses-midwives/hours-of-work/42B-night-shift-rostering-principles-other-than-permanent-night.md"};function o(a,e,h,p,g,l){return r(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="_42b-night-shift-rostering-principles-other-than-permanent-night" tabindex="-1">42B. Night Shift Rostering Principles Other Than Permanent Night <a class="header-anchor" href="#_42b-night-shift-rostering-principles-other-than-permanent-night" aria-label="Permalink to &quot;42B. Night Shift Rostering Principles Other Than Permanent Night&quot;">​</a></h1><p>shift employees) Note: This clause does not apply to casual Employees.</p><p><strong>42B.1</strong> General</p><p>The purpose of this clause is to support and give effect to those parts of the ‘Developing Employee-Centred Rostering Principles’ Report and Recommendations with respect to rostering duty, particularly in relation to:</p><p><strong>(a)</strong> offering flexibility in how night duty is rostered is important for nurses and midwives to be able to support their health and wellbeing. It is important to support and encourage staff to have input into how their night duty is rostered; and</p><p><strong>(b)</strong> Giving nurses and midwives a choice of permanent night duty, rostered blocks of night duty or ad hoc rostered night duty may have a positive impact on staff satisfaction. Ensure clear processes are in place to support this so that there is a fair allocation of non-permanent night duty.</p><p><strong>42B.2</strong> Night shift – rostering in blocks</p><p>Where night shift is performed by Employees who are not permanent night shift employees as defined at <a href="/eba/ebas/nurses-midwives/hours-of-work/42A-permanent-night-shift.html">clause 42A.1</a>, the Employer will, by not later than 30 November 2024, establish rostering principles to provide greater choice as to when and how night shift work is performed, including in planned blocks across a 12-month period.</p><p><strong>42B.3</strong> Break after night shifts</p><p>An Employee, other than a permanent night shift employee, required to work night shifts must have a minimum 47 hours break before working other shifts unless requested by the Employer to return earlier.</p><p><strong>42B.4</strong> Review</p><p>The Employers will work with the ANMF to evaluate the changes above to ensure there are no unintended consequences, with reports being provided to the WIC twice yearly or as otherwise determined by the WIC.</p>',12)])])}const f=t(s,[["render",o]]);export{c as __pageData,f as default};
